import { ButtonGroup, Button, VStack, Heading, Text } from "@chakra-ui/react";
import { Formik, Form } from 'formik';
import TextField from "../TextField";
import { useContext } from "react";
import { AccountContext } from "../AccountContext";

const KeyAuth = () => {
  const { setUser } = useContext(AccountContext);

  return (
    <Formik
      initialValues={{ key: "" }}  // only the key field
      onSubmit={(values, actions) => {
        console.log(values);  // logs { key: "entered-key" }
        // Handle key validation or user authentication logic here
      }}
    >
      {() => (
        <VStack
          as={Form}
          w={{ base: "90%", md: "500px" }}
          m="auto"
          justify="center"
          h="100vh"
          spacing="1rem"
        >
          <Heading>Key Validation</Heading>
          <Text as="p" color="red.500"> </Text>
          <TextField
            name="key"
            placeholder="Enter Private Key"
            type="password"
            autoComplete="off"
            label="Key"
          />

          <ButtonGroup pt="1rem">
            <Button colorScheme="green" type="submit">
              Validate
            </Button>
          </ButtonGroup>
        </VStack>
      )}
    </Formik>
  );
};

export default KeyAuth;
